UPDATE indicator_mapping
SET source_system = #{sourceSystem},
    source_code = #{sourceCode},
    source_name = #{sourceName},
    target_indicator_code = #{targetIndicatorCode},
    unit_conversion_expr = #{unitConversionExpr},
    quality_rule = #{qualityRule, jdbcType=OTHER, typeHandler=xenosoft.imldintelligence.common.mybatis.JsonNodeTypeHandler},
    status = #{status}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

UPDATE indicator_mapping
SET status = 'INACTIVE'
WHERE tenant_id = #{tenantId}
  AND id = #{id}
